import * as XLSX from 'xlsx';
import dayjs from 'dayjs';

export const processCombinedData = (csvData, excelRaw) => {
  // --- 1. PROCESAR EXCEL (EASY DOCKING - ARRIBADOS FÍSICOS) ---
  const workbook = XLSX.read(excelRaw, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const rawMatrix = XLSX.utils.sheet_to_json(sheet, { header: 1 });

  const headers = rawMatrix[3]?.map(h => String(h).trim()) || []; 
  const dataRows = rawMatrix.slice(4);

  const easyDockingClean = dataRows.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  }).filter(item => 
    String(item['TIPO DE OPERACION']).toUpperCase() === "DESCARGA" && 
    String(item['Accion']).toLowerCase() === "add"
  );

  // SUMA REAL DE PIEZAS QUE ENTRARON (ARRIBADOS)
  const totalArribadosFisicos = easyDockingClean.reduce((acc, curr) => {
    return acc + (parseFloat(curr['CANT PAQUETES']) || 0);
  }, 0);

  // --- 2. PROCESAR CSV (TMS - TOTAL PIEZAS SISTEMA) ---
  // Contamos TODOS los registros de la columna Shipment ID (todas las filas)
  const totalPiezasSistema = csvData.filter(d => d['Shipment ID']).length;

  // --- 3. EFICIENCIA ---
  // Relación entre lo que entró físicamente vs lo que el sistema esperaba
  const eficiencia = totalPiezasSistema > 0 
    ? ((totalArribadosFisicos / totalPiezasSistema) * 100).toFixed(2) 
    : "0.00";

  // --- 4. GRÁFICA ---
  const franjas = Array.from({length: 19}, (_, i) => `${(i + 5).toString().padStart(2, '0')}:00`);
  const chartMap = {};
  franjas.forEach(h => chartMap[h] = { hora: h, arribo: 0, bipeo: 0 });

  easyDockingClean.forEach(row => {
    const hora = dayjs(row['Fecha y Hora']).format('HH:00');
    if (chartMap[hora]) chartMap[hora].arribo += (parseFloat(row['CANT PAQUETES']) || 0);
  });

  return {
    kpis: {
      total: totalPiezasSistema.toLocaleString(), // Conteo total de Shipment ID
      arribados: totalArribadosFisicos.toLocaleString(), // Suma de CANT PAQUETES
      eficiencia: eficiencia
    },
    chartData: Object.values(chartMap),
    tableData: franjas.map(h => ({
      intervalo: h,
      etiquetado: 1000,
      piezas: chartMap[h].bipeo,
      usuarios: 12
    })),
    matrix: {
      chasis: easyDockingClean.filter(d => String(d['TRANSPORTE']).includes('Chasis')).length,
      camioneta: easyDockingClean.filter(d => String(d['TRANSPORTE']).toLowerCase().includes('Camioneta')).length,
      semi: easyDockingClean.filter(d => String(d['TRANSPORTE']).includes('Semi')).length
    }
  };
};
